unit lipdecide;

{$mode objfpc}

interface

uses
  globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

uses
  Math;

const
  LIC_COUNT = 15;

type
  TPointIndex = integer;

function PowerOfTen(Exponent: integer): real;
var
  i: integer;
begin
  Result := 1.0;
  if Exponent > 0 then
  begin
    for i := 1 to Exponent do
      Result := Result * 10.0;
  end
  else if Exponent < 0 then
  begin
    for i := 1 to -Exponent do
      Result := Result / 10.0;
  end;
end;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  diff, maxAbs, tolerance: real;
  exponent: integer;
begin
  diff := Abs(A - B);
  maxAbs := Abs(A);
  if Abs(B) > maxAbs then
    maxAbs := Abs(B);
  if maxAbs = 0.0 then
  begin
    Result := EQ;
    exit;
  end;

  exponent := 0;
  while maxAbs >= 10.0 do
  begin
    maxAbs := maxAbs / 10.0;
    Inc(exponent);
  end;
  while (maxAbs > 0.0) and (maxAbs < 1.0) do
  begin
    maxAbs := maxAbs * 10.0;
    Dec(exponent);
  end;

  tolerance := 0.5 * PowerOfTen(exponent - 5);
  if diff <= tolerance then
    Result := EQ
  else if A < B then
    Result := LT
  else
    Result := GT;
end;

function DistanceSquared(const I1, I2: TPointIndex): real;
var
  dx, dy: real;
begin
  dx := X[I2] - X[I1];
  dy := Y[I2] - Y[I1];
  Result := Sqr(dx) + Sqr(dy);
end;

function DistanceBetween(const I1, I2: TPointIndex): real;
begin
  Result := Sqrt(DistanceSquared(I1, I2));
end;

function TriangleArea(const I1, I2, I3: TPointIndex): real;
var
  areaValue: real;
begin
  areaValue := ((X[I1] * (Y[I2] - Y[I3])) +
                (X[I2] * (Y[I3] - Y[I1])) +
                (X[I3] * (Y[I1] - Y[I2]))) / 2.0;
  if REALCOMPARE(areaValue, 0.0) = LT then
    areaValue := -areaValue;
  Result := areaValue;
end;

function PointsCoincident(const I1, I2: TPointIndex): boolean;
begin
  Result := (REALCOMPARE(X[I1], X[I2]) = EQ) and (REALCOMPARE(Y[I1], Y[I2]) = EQ);
end;

function MaxReal(const A, B: real): real;
begin
  if REALCOMPARE(A, B) = GT then
    Result := A
  else
    Result := B;
end;

function PointsWithinCircleRadius(const I1, I2, I3: TPointIndex; const Radius: real): boolean;
var
  d12, d23, d13, maxDist, areaValue, circumRadius: real;
  comp: COMPTYPE;
begin
  Result := false;
  if REALCOMPARE(Radius, 0.0) = LT then
    exit;

  d12 := DistanceBetween(I1, I2);
  d23 := DistanceBetween(I2, I3);
  d13 := DistanceBetween(I1, I3);

  maxDist := MaxReal(d12, d23);
  maxDist := MaxReal(maxDist, d13);
  comp := REALCOMPARE(maxDist, 2.0 * Radius);
  if comp = GT then
  begin
    Result := false;
    exit;
  end;

  areaValue := TriangleArea(I1, I2, I3);
  if REALCOMPARE(areaValue, 0.0) = EQ then
  begin
    comp := REALCOMPARE(maxDist / 2.0, Radius);
    Result := (comp = LT) or (comp = EQ);
    exit;
  end;

  circumRadius := (d12 * d23 * d13) / (4.0 * areaValue);
  comp := REALCOMPARE(circumRadius, Radius);
  Result := (comp = LT) or (comp = EQ);
end;

function ComputeAngle(const I1, I2, I3: TPointIndex; out Angle: real): boolean;
var
  v1x, v1y, v2x, v2y, len1, len2, crossProd, dotProd: real;
begin
  Angle := 0.0;
  v1x := X[I1] - X[I2];
  v1y := Y[I1] - Y[I2];
  v2x := X[I3] - X[I2];
  v2y := Y[I3] - Y[I2];

  len1 := Sqrt(Sqr(v1x) + Sqr(v1y));
  len2 := Sqrt(Sqr(v2x) + Sqr(v2y));

  if (REALCOMPARE(len1, 0.0) = EQ) or (REALCOMPARE(len2, 0.0) = EQ) then
  begin
    Result := false;
    exit;
  end;

  crossProd := (v1x * v2y) - (v1y * v2x);
  dotProd := (v1x * v2x) + (v1y * v2y);

  Angle := ArcTan2(crossProd, dotProd);
  if REALCOMPARE(Angle, 0.0) = LT then
    Angle := Angle + 2.0 * globals.PI;

  Result := true;
end;

function DistanceFromPointToLine(const PointIdx, StartIdx, EndIdx: TPointIndex): real;
var
  x0, y0, x1, y1, x2, y2: real;
  dx, dy, numerator, denominator: real;
begin
  x0 := X[PointIdx];
  y0 := Y[PointIdx];
  x1 := X[StartIdx];
  y1 := Y[StartIdx];
  x2 := X[EndIdx];
  y2 := Y[EndIdx];

  dx := x2 - x1;
  dy := y2 - y1;
  denominator := Sqrt(Sqr(dx) + Sqr(dy));

  if REALCOMPARE(denominator, 0.0) = EQ then
  begin
    Result := Sqrt(Sqr(x0 - x1) + Sqr(y0 - y1));
    exit;
  end;

  numerator := Abs((dy * x0) - (dx * y0) + (x2 * y1) - (y2 * x1));
  Result := numerator / denominator;
end;

function DetermineQuadrant(const PointIdx: TPointIndex): integer;
var
  xComp, yComp: COMPTYPE;
begin
  xComp := REALCOMPARE(X[PointIdx], 0.0);
  yComp := REALCOMPARE(Y[PointIdx], 0.0);

  if ((xComp = GT) or (xComp = EQ)) and ((yComp = GT) or (yComp = EQ)) then
    exit(1);

  if (xComp = LT) and ((yComp = GT) or (yComp = EQ)) then
    exit(2);

  if ((xComp = LT) or (xComp = EQ)) and (yComp = LT) then
    exit(3);

  exit(4);
end;

function EvaluateLIC1: boolean;
var
  i: integer;
  distanceValue: real;
begin
  Result := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    distanceValue := DistanceBetween(i, i + 1);
    if REALCOMPARE(distanceValue, PARAMETERS.LENGTH1) = GT then
    begin
      Result := true;
      exit;
    end;
  end;
end;

function EvaluateLIC2: boolean;
var
  i: integer;
begin
  Result := false;
  if NUMPOINTS < 3 then
    exit;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if not PointsWithinCircleRadius(i, i + 1, i + 2, PARAMETERS.RADIUS1) then
    begin
      Result := true;
      exit;
    end;
  end;
end;

function EvaluateLIC3: boolean;
var
  i: integer;
  angleValue, lowerBound, upperBound: real;
begin
  Result := false;
  if NUMPOINTS < 3 then
    exit;

  lowerBound := globals.PI - PARAMETERS.EPSILON;
  upperBound := globals.PI + PARAMETERS.EPSILON;

  for i := 1 to NUMPOINTS - 2 do
  begin
    if ComputeAngle(i, i + 1, i + 2, angleValue) then
    begin
      if (REALCOMPARE(angleValue, lowerBound) = LT) or
         (REALCOMPARE(angleValue, upperBound) = GT) then
      begin
        Result := true;
        exit;
      end;
    end;
  end;
end;

function EvaluateLIC4: boolean;
var
  i: integer;
  areaValue: real;
begin
  Result := false;
  if NUMPOINTS < 3 then
    exit;
  for i := 1 to NUMPOINTS - 2 do
  begin
    areaValue := TriangleArea(i, i + 1, i + 2);
    if REALCOMPARE(areaValue, PARAMETERS.AREA1) = GT then
    begin
      Result := true;
      exit;
    end;
  end;
end;

function EvaluateLIC5: boolean;
var
  startIdx, offset, quadrantsUsed: integer;
  quadFlags: array[1..4] of boolean;
  quadIndex: integer;
begin
  Result := false;
  if PARAMETERS.Q_PTS > NUMPOINTS then
    exit;

  for startIdx := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    quadFlags[1] := false;
    quadFlags[2] := false;
    quadFlags[3] := false;
    quadFlags[4] := false;

    for offset := 0 to PARAMETERS.Q_PTS - 1 do
    begin
      quadIndex := DetermineQuadrant(startIdx + offset);
      quadFlags[quadIndex] := true;
    end;

    quadrantsUsed := 0;
    for quadIndex := 1 to 4 do
      if quadFlags[quadIndex] then
        Inc(quadrantsUsed);

    if quadrantsUsed > PARAMETERS.QUADS then
    begin
      Result := true;
      exit;
    end;
  end;
end;

function EvaluateLIC6: boolean;
var
  i: integer;
  deltaX: real;
begin
  Result := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    deltaX := X[i + 1] - X[i];
    if REALCOMPARE(deltaX, 0.0) = LT then
    begin
      Result := true;
      exit;
    end;
  end;
end;

function EvaluateLIC7: boolean;
var
  startIdx, endIdx, pointIdx: integer;
  distanceValue: real;
begin
  Result := false;
  if NUMPOINTS < 3 then
    exit;
  if PARAMETERS.N_PTS > NUMPOINTS then
    exit;

  for startIdx := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    endIdx := startIdx + PARAMETERS.N_PTS - 1;

    if PointsCoincident(startIdx, endIdx) then
    begin
      for pointIdx := startIdx to endIdx do
      begin
        if (pointIdx = startIdx) or (pointIdx = endIdx) then
          continue;
        distanceValue := DistanceBetween(pointIdx, startIdx);
        if REALCOMPARE(distanceValue, PARAMETERS.DIST) = GT then
        begin
          Result := true;
          exit;
        end;
      end;
    end
    else
    begin
      for pointIdx := startIdx + 1 to endIdx - 1 do
      begin
        distanceValue := DistanceFromPointToLine(pointIdx, startIdx, endIdx);
        if REALCOMPARE(distanceValue, PARAMETERS.DIST) = GT then
        begin
          Result := true;
          exit;
        end;
      end;
    end;
  end;
end;

function EvaluateLIC8: boolean;
var
  i, j, limit: integer;
  distanceValue: real;
begin
  Result := false;
  if NUMPOINTS < 3 then
    exit;

  limit := NUMPOINTS - PARAMETERS.K_PTS - 1;
  if limit < 1 then
    exit;

  for i := 1 to limit do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    distanceValue := DistanceBetween(i, j);
    if REALCOMPARE(distanceValue, PARAMETERS.LENGTH1) = GT then
    begin
      Result := true;
      exit;
    end;
  end;
end;

function EvaluateLIC9: boolean;
var
  i, j, k, limit: integer;
begin
  Result := false;
  if NUMPOINTS < 5 then
    exit;

  limit := NUMPOINTS - (PARAMETERS.A_PTS + PARAMETERS.B_PTS) - 2;
  if limit < 1 then
    exit;

  for i := 1 to limit do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    if not PointsWithinCircleRadius(i, j, k, PARAMETERS.RADIUS1) then
    begin
      Result := true;
      exit;
    end;
  end;
end;

function EvaluateLIC10: boolean;
var
  i, j, k, limit: integer;
  angleValue, lowerBound, upperBound: real;
begin
  Result := false;
  if NUMPOINTS < 5 then
    exit;

  lowerBound := globals.PI - PARAMETERS.EPSILON;
  upperBound := globals.PI + PARAMETERS.EPSILON;

  limit := NUMPOINTS - (PARAMETERS.C_PTS + PARAMETERS.D_PTS) - 2;
  if limit < 1 then
    exit;

  for i := 1 to limit do
  begin
    j := i + PARAMETERS.C_PTS + 1;
    k := j + PARAMETERS.D_PTS + 1;
    if ComputeAngle(i, j, k, angleValue) then
    begin
      if (REALCOMPARE(angleValue, lowerBound) = LT) or
         (REALCOMPARE(angleValue, upperBound) = GT) then
      begin
        Result := true;
        exit;
      end;
    end;
  end;
end;

function EvaluateLIC11: boolean;
var
  i, j, k, limit: integer;
  areaValue: real;
begin
  Result := false;
  if NUMPOINTS < 5 then
    exit;

  limit := NUMPOINTS - (PARAMETERS.E_PTS + PARAMETERS.F_PTS) - 2;
  if limit < 1 then
    exit;

  for i := 1 to limit do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    areaValue := TriangleArea(i, j, k);
    if REALCOMPARE(areaValue, PARAMETERS.AREA1) = GT then
    begin
      Result := true;
      exit;
    end;
  end;
end;

function EvaluateLIC12: boolean;
var
  i, j, limit: integer;
  deltaX: real;
begin
  Result := false;
  if NUMPOINTS < 3 then
    exit;

  limit := NUMPOINTS - PARAMETERS.G_PTS - 1;
  if limit < 1 then
    exit;

  for i := 1 to limit do
  begin
    j := i + PARAMETERS.G_PTS + 1;
    deltaX := X[j] - X[i];
    if REALCOMPARE(deltaX, 0.0) = LT then
    begin
      Result := true;
      exit;
    end;
  end;
end;

function EvaluateLIC13: boolean;
var
  i, j, limit: integer;
  distanceValue: real;
  greaterFound, lesserFound: boolean;
  cmpGreater, cmpLesser: COMPTYPE;
begin
  Result := false;
  if NUMPOINTS < 3 then
    exit;

  limit := NUMPOINTS - PARAMETERS.K_PTS - 1;
  if limit < 1 then
    exit;

  greaterFound := false;
  lesserFound := false;

  for i := 1 to limit do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    distanceValue := DistanceBetween(i, j);

    cmpGreater := REALCOMPARE(distanceValue, PARAMETERS.LENGTH1);
    if cmpGreater = GT then
      greaterFound := true;

    cmpLesser := REALCOMPARE(distanceValue, PARAMETERS.LENGTH2);
    if cmpLesser = LT then
      lesserFound := true;

    if greaterFound and lesserFound then
    begin
      Result := true;
      exit;
    end;
  end;

  Result := greaterFound and lesserFound;
end;

function EvaluateLIC14: boolean;
var
  i, j, k, limit: integer;
  cannotContainFound, canContainFound: boolean;
begin
  Result := false;
  if NUMPOINTS < 5 then
    exit;

  limit := NUMPOINTS - (PARAMETERS.A_PTS + PARAMETERS.B_PTS) - 2;
  if limit < 1 then
    exit;

  cannotContainFound := false;
  canContainFound := false;

  for i := 1 to limit do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;

    if not PointsWithinCircleRadius(i, j, k, PARAMETERS.RADIUS1) then
      cannotContainFound := true;

    if PointsWithinCircleRadius(i, j, k, PARAMETERS.RADIUS2) then
      canContainFound := true;

    if cannotContainFound and canContainFound then
    begin
      Result := true;
      exit;
    end;
  end;

  Result := cannotContainFound and canContainFound;
end;

function EvaluateLIC15: boolean;
var
  i, j, k, limit: integer;
  areaValue: real;
  greaterFound, lesserFound: boolean;
  cmpGreater, cmpLesser: COMPTYPE;
begin
  Result := false;
  if NUMPOINTS < 5 then
    exit;

  limit := NUMPOINTS - (PARAMETERS.E_PTS + PARAMETERS.F_PTS) - 2;
  if limit < 1 then
    exit;

  greaterFound := false;
  lesserFound := false;

  for i := 1 to limit do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;

    areaValue := TriangleArea(i, j, k);

    cmpGreater := REALCOMPARE(areaValue, PARAMETERS.AREA1);
    if cmpGreater = GT then
      greaterFound := true;

    cmpLesser := REALCOMPARE(areaValue, PARAMETERS.AREA2);
    if cmpLesser = LT then
      lesserFound := true;

    if greaterFound and lesserFound then
    begin
      Result := true;
      exit;
    end;
  end;

  Result := greaterFound and lesserFound;
end;

procedure PopulateCMV;
begin
  CMV[1] := EvaluateLIC1;
  CMV[2] := EvaluateLIC2;
  CMV[3] := EvaluateLIC3;
  CMV[4] := EvaluateLIC4;
  CMV[5] := EvaluateLIC5;
  CMV[6] := EvaluateLIC6;
  CMV[7] := EvaluateLIC7;
  CMV[8] := EvaluateLIC8;
  CMV[9] := EvaluateLIC9;
  CMV[10] := EvaluateLIC10;
  CMV[11] := EvaluateLIC11;
  CMV[12] := EvaluateLIC12;
  CMV[13] := EvaluateLIC13;
  CMV[14] := EvaluateLIC14;
  CMV[15] := EvaluateLIC15;
end;

procedure PopulatePUM;
var
  i, j: integer;
begin
  for i := 1 to LIC_COUNT do
  begin
    for j := 1 to LIC_COUNT do
    begin
      if i = j then
        continue;

      case LCM[i, j] of
        NOTUSED:
          PUM[i, j] := true;
        ANDD:
          PUM[i, j] := CMV[i] and CMV[j];
        ORR:
          PUM[i, j] := CMV[i] or CMV[j];
      end;
    end;
  end;
end;

procedure PopulateFUV;
var
  i, j: integer;
  rowAllTrue: boolean;
begin
  for i := 1 to LIC_COUNT do
  begin
    rowAllTrue := true;
    for j := 1 to LIC_COUNT do
    begin
      if not PUM[i, j] then
      begin
        rowAllTrue := false;
        break;
      end;
    end;
    FUV[i] := (not PUM[i, i]) or rowAllTrue;
  end;
end;

procedure DetermineLaunchDecision;
var
  i: integer;
begin
  LAUNCH := true;
  for i := 1 to LIC_COUNT do
  begin
    if not FUV[i] then
    begin
      LAUNCH := false;
      exit;
    end;
  end;
end;

procedure DECIDE;
begin
  PopulateCMV;
  PopulatePUM;
  PopulateFUV;
  DetermineLaunchDecision;
end;

end.
